import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  computed,
  inject,
  signal,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ApiService } from '../core/api.service';
import { Opportunity, STAGES, Stage } from '../core/models';

@Component({
  selector: 'app-pipeline',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './pipeline.component.html',
  styleUrl: './pipeline.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class PipelineComponent implements OnInit {
  private readonly api = inject(ApiService);
  readonly stages = STAGES;

  loading = signal(true);
  dragId = signal<string | null>(null);
  dragOverStage = signal<Stage | null>(null);

  opportunities = signal<Opportunity[]>([]);

  readonly columns = computed(() =>
    this.stages.map((stage) => {
      const items = this.opportunities().filter((o) => o.stage === stage);
      return {
        stage,
        items,
        total: items.reduce((sum, o) => sum + o.amount, 0),
        cls: 'stage-' + stage.toLowerCase(),
      };
    }),
  );

  async ngOnInit(): Promise<void> {
    this.loading.set(true);
    try {
      this.opportunities.set(await this.api.listOpportunities());
    } catch {
      /* 401 handled centrally; otherwise the board renders empty columns. */
    } finally {
      this.loading.set(false);
    }
  }

  onDragStart(id: string): void {
    this.dragId.set(id);
  }

  onDragOver(event: DragEvent, stage: Stage): void {
    event.preventDefault();
    this.dragOverStage.set(stage);
  }

  onDrop(stage: Stage): void {
    void this.moveTo(this.dragId(), stage);
    this.dragId.set(null);
    this.dragOverStage.set(null);
  }

  /** Optimistically move a card to a new stage, then persist it. */
  async moveTo(id: string | null, stage: Stage): Promise<void> {
    if (!id) return;
    const previous = this.opportunities().find((o) => o.id === id)?.stage;
    if (!previous || previous === stage) return;
    this.apply(id, stage);
    try {
      await this.api.updateOpportunityStage(id, stage);
    } catch {
      // Revert on failure so the board reflects the persisted state.
      this.apply(id, previous);
    }
  }

  private apply(id: string, stage: Stage): void {
    this.opportunities.update((list) =>
      list.map((o) => (o.id === id ? { ...o, stage } : o)),
    );
  }
}
